【结构分析报告（口播向）】
- 结构性原因：通过FAB结构清晰传达产品特性，并结合场景化描述增强吸引力，同时通过异议处理降低决策门槛。

【结构拆解 JSON】
{
  "一、文案目标": [
    {
      "字段": "核心转化目标",
      "解析": "促进购买；引导用户尝试产品"
    },
    {
      "字段": "目标用户所处认知阶段",
      "解析": "已知产品，但需要激发兴趣和信任；可能处于考虑阶段"
    },
    {
      "字段": "使用场景（冷启动 / 转化 / 复购 / 品牌）",
      "解析": "冷启动；吸引新用户尝试"
    }
  ],
  "二、宏观结构": [
    {
      "字段": "AIDA",
      "解析": "否；没有明显展示注意、兴趣、欲望、行动的逻辑结构"
    },
    {
      "字段": "PAS",
      "解析": "否；没有明确的痛点、解决方案、证据结构"
    },
    {
      "字段": "FAB",
      "解析": "是；有特征（F）、优势（A）、利益（B）的描述"
    },
    {
      "字段": "Before–After–Bridge",
      "解析": "否；没有明显的对比或转折结构"
    },
    {
      "字段": "4Ps",
      "解析": "否；没有体现产品、价格、渠道、促销的结构"
    },
    {
      "字段": "Hero's Journey",
      "解析": "否；没有英雄旅程的叙事结构"
    }
  ],
  "三、心理驱动": [
    {
      "字段": "用户核心动机",
      "解析": "满足味觉享受；寻求健康零食；满足对辣味的喜好"
    },
    {
      "字段": "使用的主要心理杠杆（最多2个）",
      "解析": "感官刺激；健康需求"
    }
  ],
  "四、表达方式": [
    {
      "字段": "痛点是否具体化",
      "解析": "否；没有明确指出用户的问题或困扰"
    },
    {
      "字段": "是否使用情绪放大（Agitate）",
      "解析": "否；没有刻意制造焦虑或问题"
    },
    {
      "字段": "Feature 是否转化为 Benefit",
      "解析": "是；如“非油炸”转化为“不油腻”"
    },
    {
      "字段": "是否通过场景而非参数说服",
      "解析": "是；通过吃辣的体验和口感描述来说服"
    }
  ],
  "五、信任与风险处理": [
    {
      "字段": "社会认同",
      "解析": "否；没有提到用户评价或大众认可"
    },
    {
      "字段": "权威背书",
      "解析": "否；没有引用专家或权威人士的推荐"
    },
    {
      "字段": "风险逆转",
      "解析": "否；没有提供退货或保证承诺"
    },
    {
      "字段": "异议处理",
      "解析": "是；针对不同口味人群提供了选择建议"
    }
  ],
  "六、摩擦分析": [
    {
      "字段": "认知摩擦",
      "解析": "中；部分信息较模糊，如“斯哈辣”未解释"
    },
    {
      "字段": "决策摩擦",
      "解析": "低；产品介绍清晰，选择路径简单"
    },
    {
      "字段": "表达冗余",
      "解析": "中；部分内容重复，如“好香、好辣、好好吃”"
    }
  ],
  "七、语气参数（1–5）": [
    {
      "字段": "正式度",
      "解析": "2分；口语化，轻松随意"
    },
    {
      "字段": "情绪强度",
      "解析": "4分；有较强的表达力和情绪表现"
    },
    {
      "字段": "权威感",
      "解析": "2分；缺乏专业术语或权威人物背书"
    },
    {
      "字段": "挑衅度",
      "解析": "2分；语气平和，没有攻击性"
    }
  ],
  "八、CTA 评估": [
    {
      "字段": "第一人称",
      "解析": "否；没有使用第一人称表述"
    },
    {
      "字段": "明确性",
      "解析": "3分；CTA不够直接，只是建议尝试"
    },
    {
      "字段": "摩擦程度",
      "解析": "中；有引导但没有强烈推动"
    },
    {
      "字段": "出现位置合理性",
      "解析": "是；出现在结尾，符合逻辑"
    }
  ],
  "总结该文案成功的结构性原因": "通过FAB结构清晰传达产品特性，并结合场景化描述增强吸引力，同时通过异议处理降低决策门槛。"
}
